1	import { google } from "@ai-sdk/google";
2	import { generateObject } from "ai";
3	import type { BrandProfile, MarketContext, RepoSnapshot } from "./schemas";
4	import { type VideoScript, VideoScriptSchema } from "./schemas";
5	
6	const MODEL_ID = "gemini-2.5-flash";
7	const MIN_TOTAL_SEC = 30;
8	const MAX_TOTAL_SEC = 60;
9	
10	type Args = {
11		snapshot: RepoSnapshot;
12		brand: BrandProfile;
13		market: MarketContext;
14	};
15	
16	export async function writeScriptFromRepo({
17		snapshot,
18		brand,
19		market,
20	}: Args): Promise<VideoScript> {
21		const system = systemPrompt(brand);
22		const user = userPrompt({ snapshot, market });
23	
24		const first = await runOnce({ system, user });
25		if (
26			totalSeconds(first) >= MIN_TOTAL_SEC &&
27			totalSeconds(first) <= MAX_TOTAL_SEC
28		) {
29			return first;
30		}
31	
32		const retryUser = `${user}\n\nIMPORTANT: previous draft totalled ${totalSeconds(
33			first,
34		)}s. The sum of all scenes' durationSec MUST be between ${MIN_TOTAL_SEC} and ${MAX_TOTAL_SEC}.`;
35		return runOnce({ system, user: retryUser });
36	}
37	
38	async function runOnce({
39		system,
40		user,
41	}: {
42		system: string;
43		user: string;
44	}): Promise<VideoScript> {
45		const { object } = await generateObject({
46			model: google(MODEL_ID),
47			schema: VideoScriptSchema,
48			schemaName: "VideoScript",
49			schemaDescription:
50				"Vertical short-form video script with hook + scenes + CTA",
51			system,
52			prompt: user,
53		});
54		return object;
55	}
56	
57	function totalSeconds(script: VideoScript): number {
58		return script.scenes.reduce((acc, s) => acc + s.durationSec, 0);
59	}
60	
61	function systemPrompt(brand: BrandProfile): string {
62		const tone = describeTone(brand);
63		return [
64			`You are a video script writer for the brand "${brand.name}".`,
65			`Voice: ${brand.voice}.`,
66			`Tone adjectives: ${tone}.`,
67			brand.rules?.dos?.length ? `Do: ${brand.rules.dos.join("; ")}.` : "",
68			brand.rules?.donts?.length ? `Don't: ${brand.rules.donts.join("; ")}.` : "",
69			"Output a 30-60 second vertical short-form script: a punchy hook, 4-8 scenes (each 2-8s), and a closing CTA.",
70			"Every scene needs concrete user-facing facts pulled from the source. No vague filler.",
71		]
72			.filter(Boolean)
73			.join(" ");
74	}
75	
76	function userPrompt({
77		snapshot,
78		market,
79	}: {
80		snapshot: RepoSnapshot;
81		market: MarketContext;
82	}): string {
83		const lines: string[] = [
84			`Repo: ${snapshot.owner}/${snapshot.name} (${snapshot.stars}★)`,
85			snapshot.description ? `Description: ${snapshot.description}` : "",
86			snapshot.primaryLanguage
87				? `Primary language: ${snapshot.primaryLanguage}`
88				: "",
89			snapshot.topics.length ? `Topics: ${snapshot.topics.join(", ")}` : "",
90			"",
91			"README excerpt:",
92			snapshot.readme.slice(0, 8_000),
93		];
94	
95		if (snapshot.recentCommits.length > 0) {
96			lines.push("", "Recent commits:");
97			for (const c of snapshot.recentCommits.slice(0, 8)) {
98				lines.push(`- ${c.message}`);
99			}
100		}
101	
102		if (market.results.length > 0) {
103			lines.push("", "Competitors / similar projects in the wild:");
104			for (const r of market.results) {
105				lines.push(`- ${r.title} — ${r.snippet.slice(0, 200)}`);
106			}
107			lines.push(
108				"",
109				"Use the competitor context to highlight a unique angle this project owns.",
110			);
111		}
112	
113		return lines.filter((l) => l !== undefined).join("\n");
114	}
115	
116	function describeTone(brand: BrandProfile): string {
117		const t = brand.tone;
118		const parts: string[] = [];
119		parts.push(t.formalCasual >= 50 ? "casual" : "formal");
120		parts.push(t.seriousPlayful >= 50 ? "playful" : "serious");
121		parts.push(t.directStorytelling >= 50 ? "story-driven" : "direct");
122		return parts.join(", ");
123	}
